#include "SYsULexer.h"
#include <fstream>
#include <iostream>
#include <sstream>
#include <string>
#include <unordered_map>
#include <vector>

// Mapping from ANTLR symbolic names to the clang -dump-tokens style names.
static const std::unordered_map<std::string, std::string> kTokenTypeMapping = {
  { "Const", "const" },
  { "Int", "int" },
  { "Void", "void" },
  { "Return", "return" },
  { "If", "if" },
  { "Else", "else" },
  { "While", "while" },
  { "Break", "break" },
  { "Continue", "continue" },

  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "LeftBrace", "l_brace" },
  { "RightBrace", "r_brace" },

  { "Semi", "semi" },
  { "Comma", "comma" },

  { "Plus", "plus" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },

  { "Equal", "equal" },
  { "EqualEqual", "equalequal" },
  { "ExclaimEqual", "exclaimequal" },
  { "Less", "less" },
  { "LessEqual", "lessequal" },
  { "Greater", "greater" },
  { "GreaterEqual", "greaterequal" },
  { "Exclaim", "exclaim" },
  { "AmpAmp", "ampamp" },
  { "PipePipe", "pipepipe" },

  { "Identifier", "identifier" },
  { "Constant", "numeric_constant" },

  { "EOF", "eof" },
};

namespace {

// Each preprocessed physical line maps to a (real_file, real_line) tuple, computed
// from the cpp-style line markers (`# linenum "filename" flags*`).
struct PhysLineLoc
{
  std::string file;
  int line = 0;
};

// Parse a single line marker.  Returns true on success and writes the new file
// name and starting real line number into the outputs.
bool
parse_line_marker(const std::string& text, std::string& file, int& realLine)
{
  // Format: `# <linenum> "<file>" <flags...>`
  size_t i = 0;
  if (i >= text.size() || text[i] != '#')
    return false;
  ++i;
  while (i < text.size() && (text[i] == ' ' || text[i] == '\t'))
    ++i;
  // linenum
  if (i >= text.size() || !std::isdigit(static_cast<unsigned char>(text[i])))
    return false;
  int n = 0;
  while (i < text.size() && std::isdigit(static_cast<unsigned char>(text[i]))) {
    n = n * 10 + (text[i] - '0');
    ++i;
  }
  while (i < text.size() && (text[i] == ' ' || text[i] == '\t'))
    ++i;
  if (i >= text.size() || text[i] != '"')
    return false;
  ++i;
  std::string fname;
  while (i < text.size() && text[i] != '"') {
    if (text[i] == '\\' && i + 1 < text.size()) {
      fname += text[i + 1];
      i += 2;
    } else {
      fname += text[i];
      ++i;
    }
  }
  if (i >= text.size())
    return false;
  file = std::move(fname);
  realLine = n;
  return true;
}

// Build the physical->real mapping by scanning the input lines.
//
// `phys` indexes are 1-based, matching ANTLR's `getLine()` convention.  Lines
// that *are* a line marker carry the file/line of the line itself (which is
// unused, since markers go to the hidden channel and we never query them).
std::vector<PhysLineLoc>
build_loc_map(const std::vector<std::string>& lines)
{
  std::vector<PhysLineLoc> out(lines.size() + 2);
  std::string currentFile;
  int nextRealLine = 1;
  for (size_t i = 0; i < lines.size(); ++i) {
    const std::string& l = lines[i];
    // Skip leading whitespace to test for `#`
    size_t k = 0;
    while (k < l.size() && (l[k] == ' ' || l[k] == '\t'))
      ++k;
    if (k < l.size() && l[k] == '#') {
      std::string file;
      int line = 0;
      if (parse_line_marker(l.substr(k), file, line)) {
        currentFile = file;
        nextRealLine = line;
      }
      // The marker line itself has no usable mapping.
      out[i + 1] = { currentFile, 0 };
      continue;
    }
    out[i + 1] = { currentFile, nextRealLine };
    ++nextRealLine;
  }
  return out;
}

} // anonymous namespace

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // Read the whole input so we can both feed it to ANTLR and build the
  // physical-line metadata table.
  std::stringstream buf;
  buf << inFile.rdbuf();
  std::string source = buf.str();

  std::vector<std::string> lines;
  {
    std::string cur;
    for (char c : source) {
      if (c == '\n') {
        lines.push_back(cur);
        cur.clear();
      } else if (c == '\r') {
        // ignore; \r\n handled when \n arrives
      } else {
        cur += c;
      }
    }
    if (!cur.empty())
      lines.push_back(cur);
  }
  auto locMap = build_loc_map(lines);

  antlr4::ANTLRInputStream input(source);
  SYsULexer lexer(&input);
  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  const auto& vocabulary = lexer.getVocabulary();

  // Track for each physical line whether we have already emitted a real token.
  std::vector<char> seenOnLine(lines.size() + 2, 0);

  // Bookkeeping for the final EOF: the last real token's location.
  std::string lastFile;
  int lastLine = 0;
  int lastEndCol = 1;

  for (auto&& token : tokens.getTokens()) {
    if (token->getChannel() != antlr4::Token::DEFAULT_CHANNEL &&
        token->getType() != antlr4::Token::EOF) {
      continue;
    }

    std::string sym(vocabulary.getSymbolicName(token->getType()));
    if (sym.empty())
      sym = "<UNKNOWN>";

    std::string kind = sym;
    auto it = kTokenTypeMapping.find(sym);
    if (it != kTokenTypeMapping.end())
      kind = it->second;

    size_t physLine = token->getLine();
    size_t col0 = token->getCharPositionInLine();
    bool isEof = token->getType() == antlr4::Token::EOF;

    std::string text = isEof ? std::string() : token->getText();

    // Resolve the source location.
    std::string locFile;
    int locLine = 0;
    int locCol = 0;
    if (isEof) {
      locFile = lastFile;
      locLine = lastLine;
      locCol = lastEndCol;
    } else {
      if (physLine >= 1 && physLine < locMap.size()) {
        locFile = locMap[physLine].file;
        locLine = locMap[physLine].line;
      }
      locCol = static_cast<int>(col0) + 1;
    }

    // [StartOfLine] : first emitted (real) token on this physical line.
    bool startOfLine = false;
    if (!isEof && physLine >= 1 && physLine < seenOnLine.size()) {
      if (!seenOnLine[physLine]) {
        startOfLine = true;
        seenOnLine[physLine] = 1;
      }
    }

    // [LeadingSpace] : preceding character on the same physical line is space
    // or tab.
    bool leadingSpace = false;
    if (!isEof && physLine >= 1 && physLine - 1 < lines.size() && col0 > 0) {
      const std::string& line = lines[physLine - 1];
      if (col0 <= line.size()) {
        char prev = line[col0 - 1];
        if (prev == ' ' || prev == '\t')
          leadingSpace = true;
      }
    }

    outFile << kind << " '" << text << "'";
    if (startOfLine)
      outFile << "\t [StartOfLine]";
    if (leadingSpace) {
      if (!startOfLine)
        outFile << "\t";
      outFile << " [LeadingSpace]";
    }
    outFile << "\tLoc=<" << locFile << ":" << locLine << ":" << locCol << ">"
            << std::endl;

    if (!isEof) {
      lastFile = locFile;
      lastLine = locLine;
      lastEndCol = locCol + static_cast<int>(text.size());
    }
  }

  return 0;
}

